class Solution(object):
    def countPartitions(self, nums):
        total = sum(nums)
        count = 0
        left = 0
        for i in range(len(nums) - 1):
            left += nums[i]
            right = total - left
            if (left - right) % 2 == 0:
                count += 1
        return count
